"use client";

import { useCallback, useMemo, useState } from "react";
import type { Margin } from "./chart-context";
import { ChartLoadingLabel } from "./chart-loading-label";
import { Line } from "./line";
import { LineChart } from "./line-chart";
import { LineLoadingPulse } from "./line-loading-pulse";
import { LINE_LOADING_LOOP_PAUSE_MS } from "./line-loading-timing";
import { LoadingGrid } from "./loading-grid";

const LOADING_DATA_KEY = "value";
const LOADING_POINT_COUNT = 7;
const DEFAULT_LOADING_STROKE = "var(--foreground)";
const DEFAULT_LOADING_GRID_STROKE =
  "color-mix(in oklch, var(--chart-grid) 50%, transparent)";
const DEFAULT_LOADING_GRID_SHIMMER_STROKE =
  "color-mix(in oklch, var(--foreground) 68%, transparent)";
const DEFAULT_LOADING_STROKE_OPACITY = 0.5;

function generateLoadingLineData(
  pointCount: number
): Record<string, unknown>[] {
  const baseDate = new Date("2025-01-01");
  return Array.from({ length: pointCount }, (_, index) => {
    const date = new Date(baseDate);
    date.setDate(baseDate.getDate() + index);
    return {
      date,
      [LOADING_DATA_KEY]: Math.round(
        110 + Math.sin(index * 1.15) * 36 + index * 9
      ),
    };
  });
}

export interface LineChartLoadingProps {
  /** Chart margins */
  margin?: Partial<Margin>;
  /** Stroke color for the animated loading segment. */
  stroke?: string;
  /** Stroke opacity for the animated loading segment. Default: 0.5 */
  strokeOpacity?: number;
  /** Grid line stroke (color and opacity via color-mix or oklch alpha). */
  gridStroke?: string;
  /** Shimmer band stroke (color and opacity via color-mix or oklch alpha). */
  gridShimmerStroke?: string;
  /** Animate a shimmer band across grid lines. Default: true */
  gridShimmer?: boolean;
  /** Shimmer band width in pixels. Default: 140 */
  gridShimmerLength?: number;
  /** Shimmer speed multiplier (higher = faster). Default: 1 */
  gridShimmerSpeed?: number;
  /** Match shimmer loop to the loading line pulse (cycle + inter-loop pause). */
  gridShimmerSync?: boolean;
  /** Centered shimmer label text. Default: "Loading" */
  label?: string;
  /** Aspect ratio as "width / height". Default: "2 / 1" */
  aspectRatio?: string;
  /** Additional class name for the container */
  className?: string;
}

export function LineChartLoading({
  margin,
  stroke = DEFAULT_LOADING_STROKE,
  strokeOpacity = DEFAULT_LOADING_STROKE_OPACITY,
  gridStroke = DEFAULT_LOADING_GRID_STROKE,
  gridShimmerStroke = DEFAULT_LOADING_GRID_SHIMMER_STROKE,
  gridShimmer = true,
  gridShimmerLength,
  gridShimmerSpeed,
  gridShimmerSync = false,
  label = "Loading",
  aspectRatio = "2 / 1",
  className = "",
}: LineChartLoadingProps) {
  const [pulseEpoch, setPulseEpoch] = useState(0);
  const data = useMemo(() => generateLoadingLineData(LOADING_POINT_COUNT), []);

  const handleCycleComplete = useCallback(() => {
    window.setTimeout(() => {
      setPulseEpoch((epoch) => epoch + 1);
    }, LINE_LOADING_LOOP_PAUSE_MS);
  }, []);

  return (
    <div className="relative size-full">
      <LineChart
        animationDuration={0}
        aspectRatio={aspectRatio}
        className={className}
        data={data}
        margin={margin}
      >
        <LoadingGrid
          key={gridShimmerSync ? `loading-grid-${pulseEpoch}` : "loading-grid"}
          shimmer={gridShimmer}
          shimmerLength={gridShimmerLength}
          shimmerSpeed={gridShimmerSpeed}
          shimmerStroke={gridShimmerStroke}
          shimmerSync={gridShimmerSync}
          stroke={gridStroke}
        />
        <Line
          dataKey={LOADING_DATA_KEY}
          fadeEdges={false}
          showHighlight={false}
          stroke="transparent"
          strokeWidth={2.5}
        />
        <LineLoadingPulse
          dataKey={LOADING_DATA_KEY}
          key={pulseEpoch}
          onCycleComplete={handleCycleComplete}
          stroke={stroke}
          strokeOpacity={strokeOpacity}
        />
      </LineChart>
      <ChartLoadingLabel text={label} />
    </div>
  );
}

export default LineChartLoading;

"use client";

import { curveNatural } from "@visx/curve";
import { LinePath } from "@visx/shape";
import { animate, motion, useMotionValue, useTransform } from "motion/react";
import {
  useCallback,
  useEffect,
  useId,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { chartCssVars, useChartStable, useYScale } from "./chart-context";
import { fadeGradientStops, resolveFadeSides } from "./fade-edges";
import {
  LINE_LOADING_PULSE_CYCLE_S,
  LINE_LOADING_PULSE_EASE,
} from "./line-loading-timing";

const CLIP_PADDING = 10;

interface PathMetrics {
  pathD: string | null;
  pathLength: number;
}

export interface LineLoadingPulseProps {
  dataKey: string;
  stroke?: string;
  /** Stroke opacity for the animated segment. Default: 0.5 */
  strokeOpacity?: number;
  strokeWidth?: number;
  onCycleComplete?: () => void;
}

function useGrowExitClip(innerWidth: number, onCycleComplete?: () => void) {
  const progress = useMotionValue(0);
  const paddedFullWidth = innerWidth + CLIP_PADDING * 2;
  const rightEdge = innerWidth + CLIP_PADDING;

  const clipWidth = useTransform(progress, (p) => {
    if (p <= 0.5) {
      return (p / 0.5) * paddedFullWidth;
    }
    const shrink = (p - 0.5) / 0.5;
    return (1 - shrink) * paddedFullWidth;
  });

  const clipX = useTransform(progress, (p) => {
    if (p <= 0.5) {
      return -CLIP_PADDING;
    }
    const shrink = (p - 0.5) / 0.5;
    return rightEdge - (1 - shrink) * paddedFullWidth;
  });

  useEffect(() => {
    if (innerWidth <= 0) {
      return;
    }

    progress.set(0);
    const controls = animate(progress, 1, {
      duration: LINE_LOADING_PULSE_CYCLE_S,
      ease: [...LINE_LOADING_PULSE_EASE],
      onComplete: () => onCycleComplete?.(),
    });

    return () => controls.stop();
  }, [innerWidth, onCycleComplete, progress]);

  return { clipX, clipWidth };
}

function LoadingGrowStroke({
  pathD,
  clipPathId,
  gradientId,
  innerHeight,
  innerWidth,
  onCycleComplete,
  stroke,
  strokeOpacity,
  strokeWidth,
}: {
  pathD: string;
  clipPathId: string;
  gradientId: string;
  innerHeight: number;
  innerWidth: number;
  onCycleComplete?: () => void;
  stroke: string;
  strokeOpacity: number;
  strokeWidth: number;
}) {
  const fadeStops = fadeGradientStops(resolveFadeSides(true));
  const clipHeight = innerHeight + CLIP_PADDING * 2;
  const { clipX, clipWidth } = useGrowExitClip(innerWidth, onCycleComplete);

  return (
    <>
      <defs>
        <clipPath id={clipPathId}>
          <motion.rect
            height={clipHeight}
            style={{ width: clipWidth, x: clipX }}
            y={-CLIP_PADDING}
          />
        </clipPath>
        <linearGradient id={gradientId} x1="0%" x2="100%" y1="0%" y2="0%">
          {fadeStops.map((stop) => (
            <stop
              key={stop.offset}
              offset={stop.offset}
              stopColor={stroke}
              stopOpacity={stop.opacity}
            />
          ))}
        </linearGradient>
      </defs>
      <path
        clipPath={`url(#${clipPathId})`}
        d={pathD}
        fill="none"
        opacity={strokeOpacity}
        stroke={`url(#${gradientId})`}
        strokeLinecap="round"
        strokeWidth={strokeWidth}
      />
    </>
  );
}

export function LineLoadingPulse({
  dataKey,
  stroke = chartCssVars.foreground,
  strokeOpacity = 0.5,
  strokeWidth = 2.5,
  onCycleComplete,
}: LineLoadingPulseProps) {
  const { renderData, xScale, xAccessor, innerWidth, innerHeight } =
    useChartStable();
  const yScale = useYScale();
  const pathRef = useRef<SVGPathElement>(null);
  const [pathMetrics, setPathMetrics] = useState<PathMetrics>({
    pathD: null,
    pathLength: 0,
  });
  const reactId = useId();
  const clipPathId = `line-loading-clip-${reactId}`;
  const gradientId = `line-loading-gradient-${reactId}`;

  const getY = useCallback(
    (d: Record<string, unknown>) => {
      const value = d[dataKey];
      return typeof value === "number" ? (yScale(value) ?? 0) : 0;
    },
    [dataKey, yScale]
  );

  // biome-ignore lint/correctness/useExhaustiveDependencies: remeasure path when chart layout or data changes
  useLayoutEffect(() => {
    const path = pathRef.current;
    if (!path) {
      return;
    }

    const pathD = path.getAttribute("d");
    const pathLength = pathD ? path.getTotalLength() : 0;
    setPathMetrics((current) =>
      current.pathD === pathD && current.pathLength === pathLength
        ? current
        : { pathD, pathLength }
    );
  }, [innerHeight, innerWidth, renderData]);

  return (
    <>
      <LinePath
        curve={curveNatural}
        data={renderData}
        innerRef={pathRef}
        stroke="transparent"
        strokeLinecap="round"
        strokeWidth={strokeWidth}
        x={(d) => xScale(xAccessor(d)) ?? 0}
        y={getY}
      />
      {pathMetrics.pathD && pathMetrics.pathLength > 0 && innerWidth > 0 ? (
        <LoadingGrowStroke
          clipPathId={clipPathId}
          gradientId={gradientId}
          innerHeight={innerHeight}
          innerWidth={innerWidth}
          onCycleComplete={onCycleComplete}
          pathD={pathMetrics.pathD}
          stroke={stroke}
          strokeOpacity={strokeOpacity}
          strokeWidth={strokeWidth}
        />
      ) : null}
    </>
  );
}

LineLoadingPulse.displayName = "LineLoadingPulse";

export default LineLoadingPulse;

/** Grow + exit timeline for `LineLoadingPulse` (seconds). */
export const LINE_LOADING_PULSE_CYCLE_S = 2.2;

/** Idle gap before the loading line pulse restarts (milliseconds). */
export const LINE_LOADING_LOOP_PAUSE_MS = 280;

export const LINE_LOADING_PULSE_EASE = [0.85, 0, 0.15, 1] as const;

"use client";

import { GridRows } from "@visx/grid";
import {
  animate,
  motion,
  useMotionValue,
  useReducedMotion,
  useTransform,
} from "motion/react";
import { useEffect, useId } from "react";
import { useChartStable, useYScale } from "./chart-context";
import {
  LINE_LOADING_LOOP_PAUSE_MS,
  LINE_LOADING_PULSE_CYCLE_S,
  LINE_LOADING_PULSE_EASE,
} from "./line-loading-timing";

const DEFAULT_SHIMMER_LENGTH_PX = 140;
const DEFAULT_SHIMMER_SPEED = 1;
const DEFAULT_GRID_STROKE =
  "color-mix(in oklch, var(--chart-grid) 50%, transparent)";
const DEFAULT_SHIMMER_STROKE =
  "color-mix(in oklch, var(--foreground) 68%, transparent)";

export interface LoadingGridProps {
  /** Number of horizontal grid lines. Default: 5 */
  numTicksRows?: number;
  /** Grid line stroke (color and opacity via color-mix or oklch alpha). */
  stroke?: string;
  /** Grid line stroke width. Default: 1 */
  strokeWidth?: number;
  /** Grid line dash array. Default: "4,4" */
  strokeDasharray?: string;
  /** Shimmer band stroke (color and opacity via color-mix or oklch alpha). */
  shimmerStroke?: string;
  /** Animate a shimmer band across grid lines. Default: true */
  shimmer?: boolean;
  /** Shimmer band width in pixels. Default: 140 */
  shimmerLength?: number;
  /** Shimmer speed multiplier (higher = faster). Default: 1 */
  shimmerSpeed?: number;
  /** Match loop timing to `LineLoadingPulse` (cycle + inter-loop pause). */
  shimmerSync?: boolean;
}

export function LoadingGrid({
  numTicksRows = 5,
  stroke = DEFAULT_GRID_STROKE,
  strokeWidth = 1,
  strokeDasharray = "4,4",
  shimmerStroke = DEFAULT_SHIMMER_STROKE,
  shimmer = true,
  shimmerLength = DEFAULT_SHIMMER_LENGTH_PX,
  shimmerSpeed = DEFAULT_SHIMMER_SPEED,
  shimmerSync = false,
}: LoadingGridProps) {
  const { innerWidth, innerHeight } = useChartStable();
  const yScale = useYScale();
  const uniqueId = useId();
  const hMaskId = `loading-grid-fade-${uniqueId}`;
  const hGradientId = `${hMaskId}-gradient`;
  const shimmerGradientId = `loading-grid-shimmer-${uniqueId}`;

  const progress = useMotionValue(0);
  const reducedMotion = useReducedMotion();
  const shimmerCycleS =
    LINE_LOADING_PULSE_CYCLE_S / Math.max(shimmerSpeed, 0.1);
  const shimmerEnabled = shimmer && reducedMotion !== true && innerWidth > 0;

  useEffect(() => {
    if (!shimmerEnabled) {
      return;
    }

    let cancelled = false;
    let timeoutId: number | undefined;
    let controls: ReturnType<typeof animate> | undefined;

    const runSyncedCycle = () => {
      if (cancelled) {
        return;
      }

      progress.set(0);
      controls = animate(progress, 1, {
        duration: shimmerCycleS,
        ease: [...LINE_LOADING_PULSE_EASE],
        onComplete: () => {
          if (cancelled) {
            return;
          }
          timeoutId = window.setTimeout(
            runSyncedCycle,
            LINE_LOADING_LOOP_PAUSE_MS
          );
        },
      });
    };

    if (shimmerSync) {
      runSyncedCycle();
      return () => {
        cancelled = true;
        controls?.stop();
        if (timeoutId !== undefined) {
          window.clearTimeout(timeoutId);
        }
      };
    }

    progress.set(0);
    controls = animate(progress, 1, {
      duration: shimmerCycleS,
      repeat: Number.POSITIVE_INFINITY,
      ease: [...LINE_LOADING_PULSE_EASE],
    });

    return () => controls?.stop();
  }, [progress, shimmerCycleS, shimmerEnabled, shimmerSync]);

  const shimmerX = useTransform(
    progress,
    (value) => -shimmerLength + value * (innerWidth + shimmerLength * 2)
  );
  const shimmerTransform = useTransform(shimmerX, (x) => `translate(${x}, 0)`);

  return (
    <g className="chart-grid chart-loading-grid">
      <defs>
        <linearGradient id={hGradientId} x1="0%" x2="100%" y1="0%" y2="0%">
          <stop offset="0%" style={{ stopColor: "white", stopOpacity: 0 }} />
          <stop offset="10%" style={{ stopColor: "white", stopOpacity: 1 }} />
          <stop offset="90%" style={{ stopColor: "white", stopOpacity: 1 }} />
          <stop offset="100%" style={{ stopColor: "white", stopOpacity: 0 }} />
        </linearGradient>
        <mask id={hMaskId}>
          <rect
            fill={`url(#${hGradientId})`}
            height={innerHeight}
            width={innerWidth}
            x="0"
            y="0"
          />
        </mask>
        {shimmerEnabled ? (
          <motion.linearGradient
            gradientTransform={shimmerTransform}
            gradientUnits="userSpaceOnUse"
            id={shimmerGradientId}
            x1={0}
            x2={shimmerLength}
            y1={0}
            y2={0}
          >
            <stop offset="0%" stopColor={shimmerStroke} stopOpacity={0} />
            <stop offset="35%" stopColor={shimmerStroke} stopOpacity={0.45} />
            <stop offset="50%" stopColor={shimmerStroke} stopOpacity={1} />
            <stop offset="65%" stopColor={shimmerStroke} stopOpacity={0.45} />
            <stop offset="100%" stopColor={shimmerStroke} stopOpacity={0} />
          </motion.linearGradient>
        ) : null}
      </defs>

      <g mask={`url(#${hMaskId})`}>
        <GridRows
          numTicks={numTicksRows}
          scale={yScale}
          stroke={stroke}
          strokeDasharray={strokeDasharray}
          strokeOpacity={1}
          strokeWidth={strokeWidth}
          width={innerWidth}
        />
        {shimmerEnabled ? (
          <GridRows
            numTicks={numTicksRows}
            scale={yScale}
            stroke={`url(#${shimmerGradientId})`}
            strokeDasharray={strokeDasharray}
            strokeOpacity={1}
            strokeWidth={strokeWidth}
            width={innerWidth}
          />
        ) : null}
      </g>
    </g>
  );
}

LoadingGrid.displayName = "LoadingGrid";

export default LoadingGrid;

